import{c as t,Q as s,j as o,m as a}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Harnesses in AI: A Deep Dive — Tejas Kumar, IBM","description":"","frontmatter":{"title":"Harnesses in AI: A Deep Dive — Tejas Kumar, IBM","date":"2026-05-17T00:00:00.000Z","creator":"Tejas Kumar","duration":"20:26","platform":"youtube","source":"https://www.youtube.com/watch?v=C_GG5g38vLU","type":"video"},"headers":[],"relativePath":"research/videos/2026-05-17-AI-Engineer-C_GG5g38.md","filePath":"research/videos/2026-05-17-AI-Engineer-C_GG5g38.md","lastUpdated":1779894392000}'),n={name:"research/videos/2026-05-17-AI-Engineer-C_GG5g38.md"};function r(i,e,h,l,g,d){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="harnesses-in-ai-a-deep-dive-—-tejas-kumar-ibm" tabindex="-1">Harnesses in AI: A Deep Dive — Tejas Kumar, IBM <a class="header-anchor" href="#harnesses-in-ai-a-deep-dive-—-tejas-kumar-ibm" aria-label="Permalink to &quot;Harnesses in AI: A Deep Dive — Tejas Kumar, IBM&quot;">​</a></h1><p><strong>來源</strong>: <a href="https://www.youtube.com/watch?v=C_GG5g38vLU" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=C_GG5g38vLU</a><strong>作者/頻道</strong>: Tejas Kumar（IBM AI Developer Advocate）/ AI Engineer <strong>發布日期</strong>: 2026-05-17 <strong>收錄日期</strong>: 2026-05-19 <strong>時長</strong>: 20:26 <strong>語言</strong>: 英文（自動字幕）</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><blockquote><p>AI harness 是圍繞模型的一切基礎設施，讓不可預測的黑盒模型能在穩定、可控環境中可靠運作。</p></blockquote><h3 id="為何需要-harness" tabindex="-1">為何需要 Harness？ <a class="header-anchor" href="#為何需要-harness" aria-label="Permalink to &quot;為何需要 Harness？&quot;">​</a></h3><p>我們都在向 Anthropic、Google 等公司「租用」模型算力。模型是黑盒：Opus 隨時可能被換成 Sonnet、context 有上限、行為不可控。Harness 的目標只有一個：<strong>reliability（可靠性）</strong>——讓 agent 做到它該做的事，無論底層模型是什麼。</p><h3 id="agent-harness-的五大組成" tabindex="-1">Agent Harness 的五大組成 <a class="header-anchor" href="#agent-harness-的五大組成" aria-label="Permalink to &quot;Agent Harness 的五大組成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>組件</th><th>說明</th></tr></thead><tbody><tr><td><strong>Tool Registry</strong></td><td>給模型用的工具集（檔案讀寫、bash、瀏覽器等）</td></tr><tr><td><strong>Model</strong></td><td>可選擇的底層模型（部分 harness 固定）</td></tr><tr><td><strong>Context 管理</strong></td><td>自動壓縮 context（如 Claude Code 的 /compact）</td></tr><tr><td><strong>Guardrails</strong></td><td>限制 max steps、max messages，超限即終止</td></tr><tr><td><strong>Agent Loop</strong></td><td>外層循環，可以是 loop 的 loop（NM loop）</td></tr><tr><td><strong>Verify Step</strong></td><td>完成後驗證：跑 lint、跑測試、確認結果是否真實成功</td></tr></tbody></table><p>Claude Code、Cursor、Codex 都是典型的 harnessed coding agent。</p><h3 id="live-demo-重點-逐步建構-harness" tabindex="-1">Live Demo 重點：逐步建構 Harness <a class="header-anchor" href="#live-demo-重點-逐步建構-harness" aria-label="Permalink to &quot;Live Demo 重點：逐步建構 Harness&quot;">​</a></h3><p><strong>任務</strong>：用 GPT-3.5 Turbo（2023 舊模型）+ Playwright 瀏覽器 agent 自動對 Hacker News 第一篇文章按讚。</p><p><strong>問題演進</strong>：</p><ol><li><strong>無 harness</strong>：Agent 說「成功了」但其實失敗（被 login 頁擋住），謊報結果</li><li><strong>加 verify step</strong>：讀取 agent tool 呼叫歷史，偵測真正的成功/失敗；agent 不再說謊</li><li><strong>加 guardrail</strong>：max_attempts=3，最多重試三次，失敗即放棄</li><li><strong>加 login handler（確定性邏輯）</strong>：每個 agent loop 前檢查是否在 login 頁；若是，deterministically 填入帳密送出表單，再通知 agent「我已幫你登入」</li></ol><p><strong>關鍵結論</strong>：整個 demo 中<strong>從未修改 prompt</strong>。Harness 的改進讓同一個 prompt 從失敗到成功——prompt engineering 不是萬能藥。</p><h3 id="ibm-實戰案例" tabindex="-1">IBM 實戰案例 <a class="header-anchor" href="#ibm-實戰案例" aria-label="Permalink to &quot;IBM 實戰案例&quot;">​</a></h3><p><strong>Open RAG</strong>：IBM 開源企業 RAG 框架，專為資料敏感環境（Slack、PDF、Teams 錄音、invoice）設計，harness 提供企業級安全性。</p><h3 id="未來展望" tabindex="-1">未來展望 <a class="header-anchor" href="#未來展望" aria-label="Permalink to &quot;未來展望&quot;">​</a></h3><ul><li><strong>2025</strong>：agents 元年</li><li><strong>2026</strong>：harnesses 元年</li><li><strong>2027（預測）</strong>：Dynamic on-the-fly harnesses — agent 在執行任務前先自動產生專屬 harness，自我感知潛在幻覺點並預先設防，類似 Plan Mode 但更強大</li></ul><hr><h2 id="逐字稿-含時間戳" tabindex="-1">逐字稿（含時間戳） <a class="header-anchor" href="#逐字稿-含時間戳" aria-label="Permalink to &quot;逐字稿（含時間戳）&quot;">​</a></h2><p><strong>[00:07 → 00:21]</strong> [music] &gt;&gt; Hello everybody. Everybody&#39;s head turned up. Hello, hi. How was lunch? Was it good? You didn&#39;t like it, no?</p><p><strong>[00:23 → 00:37]</strong> It&#39;s like British food. Anyway, hi. I&#39;m Tejas. I&#39;ll be your first speaker this afternoon. Tejas, that&#39;s pronounced like Tejas. Don&#39;t worry, I&#39;m not — Hopefully my joy in AI is</p><p><strong>[00:39 → 00:53]</strong> absolute joy to learn from the best. Today, I&#39;m a AI developer advocate at IBM where we do things with AI, believe or not. We train frontier models, we build harnesses. It&#39;s really a fun lab to work in.</p><p><strong>[00:55 → 01:10]</strong> But that&#39;s not what I&#39;m here to talk to you about today. Today, I&#39;m here to talk to you about AI harnesses. Before I move forward, I would love to just have a show of hands. How many of you are like confident in your understanding of AI harnesses?</p><p><strong>[01:11 → 01:25]</strong> Okay, this is my hope. I want you to — if I ask you this at the end of the talk, right? — I want you to be like, oh, I get it now. That&#39;s the whole point. I have literally nothing to gain from this other than shared knowledge, okay?</p><p><strong>[01:28 → 01:42]</strong> Because also this term is kind of everywhere. And it means different things to different people — like in the machine learning world, it means like a glorified test suite for machine learning models. But in the AI world, it means something different.</p><p><strong>[01:44 → 01:58]</strong> I want to start by talking about why harness. Like why do we use harnesses? And the reason for this is because we pay rent to companies that give us compute, give us inference, give us tokens in return.</p><p><strong>[02:01 → 02:15]</strong> Some of you maybe work for companies that have frontier models like Anthropic or Google or whatever and you maybe — what was the term? — token billionaires, yeah? But the vast majority of us aren&#39;t token billionaires. We pay rent. We literally pay $20 a month for Claude Pro.</p><p><strong>[02:17 → 02:32]</strong> And the model you rent is a black box. Like they could at any time — I&#39;m not saying they do, but they could — if Opus is somehow not available, they could serve you Sonnet even though it says Opus. You would never know, right?</p><p><strong>[02:34 → 02:49]</strong> Variables that we cannot control. So why harness? Because the name of the game with harness is reliability. It&#39;s making sure that the agents we build do what they do, period. Irrespective of the black box model.</p><p><strong>[02:51 → 03:05]</strong> Now that we understand why harness, let&#39;s talk about what a harness even is from first principles. Like let&#39;s take it all the way back to harnesses that we know and understand.</p><p><strong>[03:06 → 03:20]</strong> This is a harness. It&#39;s like mountain climbers literally will harness themselves to a mountain because it&#39;s stable. And they can&#39;t go off the rails, literally.</p><p><strong>[03:22 → 03:36]</strong> They anchor themselves so that they can&#39;t drift too far. Okay, that&#39;s what a harness is by design. Do you have any dog owners here? You walk your dog on a harness — because your dog doesn&#39;t go and bankrupt you with tokens.</p><p><strong>[03:38 → 03:52]</strong> That&#39;s what a harness is. But the problem is if we think about what harness, there&#39;s really two types. There&#39;s one from the machine learning world, which is kind of like a test suite and a test runner.</p><p><strong>[03:54 → 04:07]</strong> That&#39;s not what we&#39;re talking about. This is AI Engineer Europe. We&#39;re going to talk today about the agent harness that is common in AI engineering.</p><p><strong>[04:10 → 04:23]</strong> The agent harness is everything around the model that gives it grounding in reality. It&#39;s literally the thing that ties it to a stable environment, okay? Claude Code, for example, can be considered an agent harness.</p><p><strong>[04:25 → 04:38]</strong> And some of you would say, oh, no, it&#39;s a coding agent. Absolutely, it&#39;s a coding agent. But it&#39;s a harnessed coding agent. An agent harness has more or less the same typical suspects — tool registry, model, context management primitives.</p><p><strong>[04:41 → 04:53]</strong> Claude Code, Cursor, Codex — they have tools to read from the file system, to write, to execute bash commands, right? They have a tool registry. They have a model.</p><p><strong>[04:57 → 05:10]</strong> Almost every harnessed agent runtime today will compact its own context, right? That&#39;s the job of the harness. Guardrails are another part of a harness. For example, max steps — anyone using max steps? Do not do more than five tool calls. That&#39;s a guardrail.</p><p><strong>[05:12 → 05:25]</strong> An agent loop is another part of an agent harness — and this is what some people will say: &quot;Wait, isn&#39;t a harness just the agent loop?&quot; No, it&#39;s the stuff around the agent loop. In fact, it could be a loop around your agent loop. An N×M loop.</p><p><strong>[05:27 → 05:41]</strong> And then finally, there&#39;s a verify step. In a coding agent, after the work is done, a verify step would be: hey, let&#39;s run lint, let&#39;s run tests, let&#39;s make sure nothing broke.</p><p><strong>[05:44 → 05:59]</strong> So almost every coding agent — you could have a harness for anything. And it&#39;s amazing because it really grounds black box models in a stable environment that you control.</p><p><strong>[06:00 → 06:14]</strong> I&#39;d like to show you a demo. We&#39;re going to build a harness — a bare bone baby&#39;s first harness. Let&#39;s call it a poor man&#39;s AI harness — so we understand from first principles how this works.</p><p><strong>[06:16 → 06:30]</strong> We&#39;re going to build a browser use agent. We&#39;re going to use a really bad model intentionally: GPT-3.5 Turbo, which is like 2023, right? But we&#39;re going to harness it so that it can actually do the job.</p><p><strong>[06:32 → 06:46]</strong> Let&#39;s get into the demo. Welcome to my project. This is the entry point.</p><p><strong>[06:48 → 07:03]</strong> So we have a model, and this is the prompt. This is the task. Upvote a story. For the purpose of this demo, we will not change the prompt at all. Because a lot of us think, hey, my agent is not doing what it&#39;s supposed to do, so I just need to prompt it harder, right? That&#39;s not always true.</p><p><strong>[07:05 → 07:20]</strong> I need to change the system prompt. We&#39;re not — we&#39;re just going to build a harness and the outcome will change. We log some things to the console and then we start a browser session.</p><p><strong>[07:22 → 07:36]</strong> A browser session — it&#39;s literally just Playwright. Where this is just a class I made with an open method that launches Chromium and gets a context and makes a page.</p><p><strong>[07:37 → 07:52]</strong> And we give that browser session to the tools. And we create a context and we give the task — meaning the prompt here — to the context. Now, create tools.</p><p><strong>[07:54 → 08:08]</strong> These tools are not invented by me. This is from OpenAI&#39;s SDK, okay? So you have the name, the description, parameters, and execute — the way you call the tool.</p><p><strong>[08:11 → 08:25]</strong> This is my context. There&#39;s nothing here. It&#39;s just a system prompt. Literally, the most basic system prompt.</p><p><strong>[08:43 → 08:58]</strong> While true — so it is an agent loop. And we get a response from the agent and we see if the response says stop, meaning the agent is done.</p><p><strong>[09:00 → 09:14]</strong> We add these events into a trace. So we just push history into a big list of history. This is just a trace, okay?</p><p><strong>[09:16 → 09:28]</strong> npm run agent. So it&#39;s going to open Chromium. It&#39;s going to — okay, Hacker News, so far so good. Click upvote. Oh, no.</p><p><strong>[09:32 → 09:46]</strong> This is a problem. So what&#39;s the solution? Prompt it harder? No. Change the system prompt. Always login with these credentials — included in the system prompt.</p><p><strong>[09:49 → 10:03]</strong> But it still clicks the upvote button and then considers it a success. It doesn&#39;t verify. This is the job of a harness, okay? So now incrementally, we&#39;re going to slowly start building our harness.</p><p><strong>[10:05 → 10:20]</strong> This is the first change we&#39;re making. We&#39;re going to create some guardrails, okay? What do our guardrails look like?</p><p><strong>[10:36 → 10:49]</strong> Max messages — meaning if you have more than this many messages, I will compress the context. These are just guardrails.</p><p><strong>[10:51 → 11:06]</strong> And max steps. If you&#39;ve exceeded this many tool calls, we will abort. These are guardrails. And of course, we abort in the agent loop whenever these conditions are breached.</p><p><strong>[11:07 → 11:21]</strong> And the second thing is we added a verify step. We have a new function called verify successful upvote. I wrote this. This is deterministic.</p><p><strong>[11:23 → 11:38]</strong> What does this do? We see if there was a browser click on the upvote and if it&#39;s actually successful. But there&#39;s also checking for failed login cases.</p><p><strong>[11:40 → 11:55]</strong> If there&#39;s a tool named harness auto login, and the message starts with failed, then we return early and say no, this failed. We&#39;re removing the lie.</p><p><strong>[11:57 → 12:10]</strong> Similarly, unrecovered login redirect: if the harness auto login didn&#39;t run and we&#39;re on the login URL, we just fail. This is what a harness does.</p><p><strong>[12:13 → 12:26]</strong> So let&#39;s run this now with the harness. It&#39;s going to come here, and now it&#39;s still failed — but look, it stopped lying. This is what a harness is supposed to do.</p><p><strong>[12:28 → 12:42]</strong> Step one to solving a problem is admitting you have one. Test-driven development vibes. So now that we&#39;re failing correctly, we can succeed.</p><p><strong>[12:44 → 12:58]</strong> The last diff: we have a whole new function called login handler. This is all it does: it runs every agent loop just before we push to the traces, and it checks the browser session&#39;s current URL.</p><p><strong>[13:00 → 13:14]</strong> If we&#39;re not on a login page, it just says cool, I have nothing for you. If you are on the login page, then it fills in credentials and submits the button — programmatically from the harness, not from the agent, deterministically and securely.</p><p><strong>[13:16 → 13:30]</strong> And it pushes a message into the queue saying: &quot;Hey, I&#39;m the harness. I logged in. You&#39;re good now.&quot;</p><p><strong>[13:32 → 13:46]</strong> The harness is literally harnessing the agent to something stable, something deterministic. That&#39;s what it&#39;s for.</p><p><strong>[13:48 → 14:03]</strong> npm run agent. It&#39;s going to open Hacker News, and when it gets to the login — now the harness step logged in, and it upvoted the first one, and it closed. Amazing.</p><p><strong>[14:05 → 14:19]</strong> Successfully upvoted. Succeeded after six iterations. And I can go into Hacker News and actually see it was upvoted. The agent used the computer, logged in as me with my harness that I just made here on stage.</p><p><strong>[14:21 → 14:36]</strong> Do you understand the role of a harness? Look at you nodding. Fantastic.</p><p><strong>[14:38 → 14:53]</strong> Let&#39;s land the plane. What does this look like in practice? Why do I care so much about harnesses? Because they run the world. Models are non-deterministic. And you want to do more with less.</p><p><strong>[14:55 → 15:09]</strong> You want to use a cheap model — like Qwen or something, or even something smaller. And with a great harness, you can go very far. At IBM, we create an open-source project — Open RAG — that allows very large companies in data-sensitive areas to perform RAG operations on Teams calls, PDFs, invoices.</p><p><strong>[15:11 → 15:23]</strong> Open RAG has a harness that provides enterprise-level security for asking questions with internal, very siloed data.</p><p><strong>[15:25 → 15:37]</strong> Let&#39;s summarize. It should not be lost on you that I did not touch the prompt once. I did not change the system prompt. We just built a harness and the outcome radically changed.</p><p><strong>[15:39 → 15:53]</strong> I hope you understand what a harness is, the value it can present, and how you can use it. What&#39;s next? It&#39;s not lost on me that 2025 was the year of agents. 2026 is the year of harnesses, I&#39;m pretty sure.</p><p><strong>[15:55 → 16:10]</strong> And I think it&#39;d be pretty cool if 2027 was the year of dynamic on-the-fly generated harnesses. You tell an agent: &quot;Buy me a flight ticket.&quot; And before doing the work, the agent creates a harness — self-aware, knowing where it might hallucinate — does the job, and returns back to you, guardrailed.</p><p><strong>[16:12 → 16:26]</strong> Dynamic on-the-fly harnesses. I think that&#39;s the next logical step towards AGI. Thank you so much. The slides are on GitHub. [music]</p><hr><h2 id="完整純文字" tabindex="-1">完整純文字 <a class="header-anchor" href="#完整純文字" aria-label="Permalink to &quot;完整純文字&quot;">​</a></h2><p>[music] Hello everybody. I&#39;m Tejas Kumar, AI Developer Advocate at IBM. Today I&#39;m here to talk to you about AI harnesses.</p><p>Why harness? Because we pay rent to black-box models — Anthropic, Google, whatever. We&#39;re not token billionaires. The model could be swapped, context is limited, behaviour is unpredictable. The name of the game with harness is <strong>reliability</strong>: making sure the agents we build do what they do, period.</p><p>What is an agent harness? Everything around the model that gives it grounding in reality — tool registry, model, context management, guardrails (max steps/messages), an agent loop, and a verify step. Claude Code is a harnessed coding agent.</p><p>Demo: We built a browser-use agent using GPT-3.5 Turbo to upvote a Hacker News post. Starting with no harness — the agent lied about success. We incrementally added: guardrails (max_attempts=3, max_messages), a deterministic verify_successful_upvote function that reads tool call history, and a login_handler that deterministically fills credentials when it detects the login page. We never changed the prompt. The harness did all the work.</p><p>IBM&#39;s Open RAG is a real-world harness providing enterprise RAG over sensitive internal data.</p><p>2025 = year of agents. 2026 = year of harnesses. 2027 = dynamic on-the-fly harnesses: agents auto-generate their own harness before starting a task.</p>',88)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
